head.script:
/**
 * @event 
 * @name onpageload 
 * @description 화면 초기화
 */
scwin.onpageload = function () {
    scwin.globalVars();
    scwin.f_OnLoad();
};



/**
 * @event 
 * @name onbeforepageunload 
 * @description 화면이 닫히기 직전에 발생하는 이벤트.
 */
scwin.onbeforepageunload = function () {
    $c.util.clearInterval('bgColorInterval');
};



/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {

    //세션정보
    const loginDTO = $c.data.getMemInfo();

    scwin.curDtm = $c.date.getServerDateTime('yyyyMMddHHmm');

    scwin.showmod = 0;
    scwin.blNo = $c.data.getParameter('blNo') ?? '';
    scwin.bookingNo = $c.data.getParameter('bookingNo') ?? '';
    scwin.cntrNo = $c.data.getParameter('cntrNo') ?? '';
    scwin.userClsCd = loginDTO.userClsCd ?? ''; //사용자구분코드 
    scwin.userId = loginDTO.userId;  //로그인아이디
    scwin.errorTxt = '<b><color=red>부킹갯수 초과 or 잔량없음</color></b>&nbsp;&nbsp;&nbsp;';
    scwin.lineCharge = '';

    // 사용자구분코드
    // 01:그룹사구분코드
    // 01:그룹사, 02:협력업체(운송), 03:선사, 04:화주, 
    // 05:자가운송업체, 06:렌터카(고객), 07:정비(고객)

    scwin.count = 0;
    scwin.bgChangeRows = [];
    scwin.oddBgColor = '';
    scwin.evenBgColor = '';

};



/**
 * @method 
 * @name f_OnLoad 
 * @description 화면로딩시
 */
scwin.f_OnLoad = function () {

    ed_regDt.setValue(scwin.curDtm);
    ed_blNo.setValue(scwin.blNo);
    ed_bookingNo.setValue(scwin.bookingNo);
    ed_cntrNo.setValue(scwin.cntrNo);

    if (scwin.userClsCd != '01' || scwin.userId == 'csssso') {  //사용자 구분 : 05
        btn_Save.hide();
        btn_ALL.hide();
        //자가업체에서 몇일전 쏜 코피노를 이용중이어서 주석처리. 윤동진대리 요청.
        //cfEnableObj(ed_regDt, false);
        //cfEnableObj(imgCalc, false);
    } else {
        if (!$c.gus.cfIsNull(ed_regDt.getValue()) ||
            !$c.gus.cfIsNull(ed_blNo.getValue()) ||
            !$c.gus.cfIsNull(ed_bookingNo.getValue()) ||
            !$c.gus.cfIsNull(ed_cntrNo.getValue())) {
            //scwin.f_Retrieve();		20150108 황창기 속도문제로 코피노 화면 조회안하도록수정		
        };
    };

    scwin.f_AllRow();

};



/**
 * @method 
 * @name f_Retrieve 
 * @description 조회
 */
scwin.f_Retrieve = function () {

    if (scwin.userClsCd != '01' || scwin.userId == 'csssso') {  //사용자 구분 : 05
        if ($c.gus.cfIsNull(ed_blNo.getValue()) &&
            $c.gus.cfIsNull(ed_bookingNo.getValue()) &&
            $c.gus.cfIsNull(ed_cntrNo.getValue())) {
            $c.win.alert('BL_NO, BOOKING_NO, CNTR_NO 중 하나는  필수입력 사항입니다.');
            return;
        };
    } else {
        if ($c.gus.cfIsNull(ed_blNo.getValue()) &&
            $c.gus.cfIsNull(ed_bookingNo.getValue()) &&
            $c.gus.cfIsNull(ed_cntrNo.getValue()) &&
            $c.gus.cfIsNull(ed_regDt.getValue())) {
            $c.win.alert('등록일자, BL_NO, BOOKING_NO, CNTR_NO 중 하나는  필수입력 사항입니다.');
            return;
        };
    };

    if (!$c.gus.cfIsNull(ed_regDt.getValue()) &&
        !$c.gus.cfValidate([ed_regDt])) {
        return;
    };

    scwin.submitExcute(sbm_Retrieve);

};



/**
 * @method 
 * @name f_Retrieve2
 * @description 조회
 */
scwin.f_Retrieve2 = function () {

    if ($c.gus.cfIsNull(ed_blNo2.getValue()) &&
        $c.gus.cfIsNull(ed_bookingNo2.getValue()) &&
        $c.gus.cfIsNull(ed_cntrNo2.getValue())) {
        $c.win.alert('BL_NO, BOOKING_NO, CNTR_NO 중 하나는  필수입력 사항입니다.');
        return;
    };

    scwin.submitExcute(sbm_Retrieve2);

};



