/**
 * @method 
 * @name f_Delete
 * @description 삭제
 */
scwin.f_Delete = async function () {

    let focusRowIdx = ds_copinoList.getRowPosition();
    let crryinoutIntendNoVal = ds_copinoList.getCellData(focusRowIdx, 'crryinoutIntendNo');

    if (!$c.gus.cfIsNull(crryinoutIntendNoVal) || crryinoutIntendNoVal != '') {
        $c.win.alert('정상 처리건은 삭제 할 수 없습니다.');
        return;
    };

    const retConfirm = await $c.win.confirm('삭제하시겠습니까?');
    if (!retConfirm) return;

    $c.data.deleteRow(ds_copinoList);
    await scwin.submitExcute(sbm_save);
    scwin.f_Retrieve();

};



/**
 * @method 
 * @name f_toExcel
 * @description 그리드 데이터 엑셀로 다운
 */
scwin.f_toExcel = async function () {

    const totCnt = ds_copinoList.getRowCount();

    if (totCnt == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    };

    const retConfirm = await $c.win.confirm('EXCEL로 다운로드 받으시겠습니까?')
    if (!retConfirm) return;

    let excelName = 'Copino 조회화면';
    const options = { sheetName: excelName, fileName: excelName + '.xlsx' };
    $c.data.downloadGridViewExcel(gr_copinoList, options);

};



/**
 * @method 
 * @name callbackExcelDownload
 * @description f_toExcel callback
 */
scwin.callbackExcelDownload = function (e) {

    if (e.clickValue) {

    };

};



/**
 * @method 
 * @name f_toExcel2
 * @description 그리드 데이터 엑셀로 다운
 */
scwin.f_toExcel2 = async function () {

    const totCnt = ds_carryincarryoutList.getRowCount();

    if (totCnt != 0) {
        const retConfirm = await $c.win.confirm('EXCEL로 다운로드 받으시겠습니까?');
        if (!retConfirm) return;

        let excelName = '반출입 예정 정보';
        const options = {
            sheetName: excelName,
            fileName: excelName + '.xlsx'
        };
        $c.data.downloadGridViewExcel(gr_carryincarryoutList, options);

    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    };

};



/**
 * @method 
 * @name f_FieldClear
 * @description 조회조건 Clear
 */
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(
        tbl_search,
        [
            ed_blNo.getValue(),
            ed_bookingNo.getValue(),
            ed_cntrNo.getValue(),
            ed_vehclNoFull.getValue()
        ]
    );
};



/**
 * @method 
 * @name f_FieldClear2
 * @description 조회조건2 Clear
 */
scwin.f_FieldClear2 = function () {

    $c.gus.cfInitObjects(tbl_search2,
        [
            ed_blNo2.getValue(),
            ed_bookingNo2.getValue(),
            ed_cntrNo2.getValue(),
            ed_vehclNo.getValue()
        ]
    );

};



/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {

    const e = await $c.sbm.execute(sbmObj);

    if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        if (e.responseJSON.resultDataSet[0].Code == -1) return;
        await scwin.submitdone(e);
    };

};



//-----------------------------------------------------------------------------
//   Submission event  
//-----------------------------------------------------------------------------

/**
 * @event 
 * @name sbm_Retrieve_submit
 * @description 조회 TR) Submission 요청 전 선처리. return false시 submission 수행 안함.
 */
scwin.sbm_Retrieve_submit = function (e) {

    jsonData = dma_condition.getJSON();

    jsonData["regDt"] = ed_regDt.getValue();
    jsonData["blNo"] = ed_blNo.getValue();
    jsonData["bookingNo"] = ed_bookingNo.getValue();
    jsonData["procCls"] = acb_procCls.getValue();
    jsonData["cntrNo"] = ed_cntrNo.getValue();
    jsonData["vehclNoFull"] = ed_vehclNoFull.getValue();
    // lc_replyCls 컴포넌트 미존재


    dma_condition.setJSON(jsonData);

};



/**
 * @event 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = function (e) {

    let submitObj = $p.getComponentById(e.id);

    switch (submitObj) {
        case sbm_Retrieve: scwin.sbm_Retrieve_submitdone(); break;
        case sbm_Retrieve2: scwin.sbm_Retrieve2_submitdone(); break;
    };

};;



/**
 * @event 
 * @name sbm_Retrieve_submitdone
 * @description 조회 TR) Response Status 코드 값이 정상 일 경우 동작.
 */
scwin.sbm_Retrieve_submitdone = function (e) {

    $c.util.clearInterval('bgColorInterval');

    gr_copinoList.setFocusedCell(0, 0);
    const focusRowIdx = ds_copinoList.getRowPosition();
    const rowData = ds_copinoList.getRowJSON(focusRowIdx);

    ed_blNo2.setValue(rowData.blNo);
    ed_bookingNo2.setValue(rowData.bookingNo);
    ed_cntrNo2.setValue(rowData.cntrNo);
    let v_overBookingYn = rowData.overBookingYn;
    let v_crryinoutIntendNo = rowData.crryinoutIntendNo;
    let v_crryinoutClsCd = rowData.crryinoutClsCd;
    let v_lineCd = rowData.lineCd;


    ed_vehclNo.setValue(ed_vehclNoFull.getValue());

    if (ed_cntrNo2.getValue().slice(0, 5) == 'EMPTY' || ed_cntrNo2.getValue() == 'ZZZZ1234567') {
        ed_cntrNo2.setValue('');
    };

    // 오류메시지에 뿌려줄 라인별 담당자정보
    let lineCharge = '';
    switch (v_lineCd) {
        case 'SIT': //sitc
            lineCharge = '담당자: 이찬재 과장( 051-630-3665, 3656 )';
            break;

        case 'NOLS': //두우해운
        case 'SOFC':
        case 'BNMS':
        case 'TCLC':
        case 'TMSC':
            lineCharge = '담당자: 문상보 대리( 051-630-3635, 3718 )';
            break;

        case 'YNK': //코홍
        case 'COH':
            lineCharge = '담당자: 김한수 과장( 051-630-3659, 3662 )';
            break;

        default:
            break;
    };


    //반출입예정번호가 없고, batch1조회 카운트값 : DECODE(COUNT(*),0,'1','0')
    //없으면 '1' 정상건, 있으면 '0' 오류건으로 표시
    if (v_overBookingYn == '0'
        && ($c.gus.cfIsNull(v_crryinoutIntendNo) || v_crryinoutIntendNo == '')) {
        let msg = scwin.errorTxt + "<b><font color='blue'>" + lineCharge + "</font></b>";
        txt_showErrMsg.setValue(msg);
        showErrMsg.show('');
    } else {
        showErrMsg.hide();
    };

    lineCharge = '';

    if (!$c.gus.cfIsNull(ed_blNo2.getValue()) ||
        !$c.gus.cfIsNull(ed_bookingNo2.getValue()) ||
        !$c.gus.cfIsNull(ed_cntrNo2.getValue())) {
        scwin.f_Retrieve2();
    };


    totalRows.setValue(ds_copinoList.getRowCount());


    $c.util.setInterval(() => {

        let allJSON = ds_copinoList.getAllJSON();

        for (let i = 0; i < allJSON.length; i++) {

            const rowData = allJSON[i];

            if (scwin.count % 2 == 0 &&
                rowData.crryinoutIntendNo == '' &&
                rowData.overBookingYn == '0') {
                gr_copinoList.setCellBackgroundColor(i, 'status', '#FBCED4');
            }
            else {
                gr_copinoList.setCellBackgroundColor(i, 'status', '');
            };


            if (scwin.count % 2 == 0 &&
                rowData.rcvDes == '동부 KBCT CY' &&
                rowData.vsslNm.slice(0, 4) != 'DPCY') {
                gr_copinoList.setCellBackgroundColor(i, 'vsslNm', '#FBCED4');
            }
            else {
                gr_copinoList.setCellBackgroundColor(i, 'vsslNm', '');
            };

        };

        scwin.count++;
    },
        { caller: gr_copinoList, delay: 1000, key: "bgColorInterval" }
    );

};



/**
 * @event 
 * @name sbm_Retrieve2_submit
 * @description 조회2 TR) Submission 요청 전 선처리. return false시 submission 수행 안함.
 */
scwin.sbm_Retrieve2_submit = function (e) {

    const jsonData = {
        'blNo': ed_blNo2.getValue(),
        'bookingNo': ed_bookingNo2.getValue(),
        'cntrNo': ed_cntrNo2.getValue(),
        // hid_crryinoutClsCd 컴포넌트 미존재
        'vehclNo': ed_vehclNo.getValue(),
    };

    dma_condition2.setJSON(jsonData);

};




