/**
 * @event 
 * @name gr_copinoList_oncellclick
 * @description Copino수신내역) 셀이 클릭된 경우 발생
 * @param {number} rowIndex
 * @param {number} columnIndex
 * @param {string} columnId
 */
scwin.gr_copinoList_oncellclick = function (rowIndex, columnIndex, columnId) {

    if (rowIndex == -1) return;

    let rowData = ds_copinoList.getRowJSON(rowIndex);

    ed_blNo2.setValue(rowData.blNo);
    ed_bookingNo2.setValue(rowData.bookingNo);
    ed_cntrNo2.setValue(rowData.cntrNo);
    let v_overBookingYn = rowData.overBookingYn;
    let v_crryinoutIntendNo = rowData.crryinoutIntendNo;
    let v_crryinoutClsCd = rowData.crryinoutClsCd;
    let v_lineCd = rowData.lineCd;


    ed_vehclNo.setValue(ed_vehclNoFull.getValue());

    if (ed_cntrNo2.getValue().slice(0, 5) == 'EMPTY' || ed_cntrNo2.getValue() == 'ZZZZ1234567') {
        ed_cntrNo2.setValue('');
    };

    //오류메시지에 뿌려줄 라인별 담당자정보
    let lineCharge = '';
    switch (v_lineCd) {
        case 'SIT': //sitc
            lineCharge = '담당자: 이찬재 과장( 051-630-3665, 3656 )';
            break;

        case 'NOLS': //두우해운
        case 'SOFC':
        case 'BNMS':
        case 'TCLC':
        case 'TMSC':
            lineCharge = '담당자: 문상보 대리( 051-630-3635, 3656 )';
            break;

        case 'YNK':
        case 'COH':
            lineCharge = '담당자: 김한수 과장( 051-630-3659, 3662 )';
            break;

        default:
            break;
    };


    //반출입예정번호가 없고, batch1조회 카운트값 : DECODE(COUNT(*),0,'1','0')
    //없으면 '1' 정상건, 있으면 '0' 오류건으로 표시
    if (v_overBookingYn == '0'
        && ($c.gus.cfIsNull(v_crryinoutIntendNo) || v_crryinoutIntendNo == '')) {
        let msg = scwin.errorTxt + "<b><font color='blue'>" + lineCharge + "</font></b>";
        txt_showErrMsg.setValue(msg);
    } else {
        showErrMsg.hide();
    };

    scwin.f_Retrieve2();

};



/**
 * @event 
 * @name gr_copinoList_oncelldblclick
 * @description Copino수신내역) 셀이 더블 클릭된 경우 발생
 * @param {number} rowIndex
 * @param {number} columnIndex
 * @param {string} columnId
 */
scwin.gr_copinoList_oncelldblclick = function (rowIndex, columnIndex, columnId) {

    // 황창기20141031 코피노저농상태 전송오류일때 부모창의 레이어 띄움
    const rowData = ds_copinoList.getRowJSON(rowIndex);
    const parentObj = $p.parent();

    if (rowData.crryinoutIntendNo == '' && rowData.overBookingYn == '0') {
        parentObj.scwin.f_HiddenDivAlert(scwin.errorTxt, scwin.lineCharge);
        showErrMsg.hide();
    };

};



