/**
 * @method 
 * @name gridFormat
 * @description 그리드 customFormatter
 */
scwin.gridFormat = function (data, formattedData, rowIndex, colIndex) {

    const colID = this.getColumnID(colIndex);
    const gridDlt = $p.getComponentById(this.getDataList());
    let rowData = gridDlt.getRowJSON(rowIndex);

    switch (colID) {
        case "status":
            if (rowData.crryinoutIntendNo == '' &&
                rowData.overBookingYn == '0') {
                this.setCellColor(rowIndex, colID, 'red');
                return '전송오류';
            } else {
                this.setCellColor(rowIndex, colID, 'blue');
                return '정상접수';
            };

        case "vsslNm":
            if (rowData.rcvDes == '동부 KBCT CY' && rowData.vsslNm.slice(0, 4) != 'DPCY') {
                this.setCellColor(rowIndex, colID, 'red');
            };
            return formattedData;

        case 'rcvDtm':
        case 'replyDtm':
        case 'sendDtm':
            return $c.date.formatDateTime(data, 'yyyy-MM-dd HH:mm');

        default: break;
    };

};



/**
 * @event 
 * @name btn_Save_onclick
 * @description 저장 버튼 클릭
 * @asis f_Save2
 */
scwin.btn_Save_onclick = async function (e) {

    if (ds_carryincarryoutList.getModifiedIndex().length <= 0) {
        $c.win.alert("변경사항이 없습니다");
        return;
    };

    const retConfirm = await $c.win.confirm("저장하시겠습니까?");
    if (!retConfirm) return;

    scwin.submitExcute(sbm_save2);

};
